import { Platform, NativeModules } from 'react-native';

const { DeviceIntegrityModule } = NativeModules;

export class DeviceIntegrityChecker {
  private static instance: DeviceIntegrityChecker;
  private cachedStatus: DeviceSecurityStatus | null = null;
  private lastCheckTimestamp: number = 0;
  private readonly CACHE_DURATION_MS = 30000; // 30 seconds

  static getInstance(): DeviceIntegrityChecker {
    if (!DeviceIntegrityChecker.instance) {
      DeviceIntegrityChecker.instance = new DeviceIntegrityChecker();
    }
    return DeviceIntegrityChecker.instance;
  }

  async checkDeviceIntegrity(): Promise<DeviceSecurityStatus> {
    const now = Date.now();
    if (this.cachedStatus && (now - this.lastCheckTimestamp) < this.CACHE_DURATION_MS) {
      return this.cachedStatus;
    }

    const failureReasons: string[] = [];

    const [isRooted, isEmulator, isDebuggerAttached, hasSecureScreen] = await Promise.all([
      this.checkRootStatus(),
      this.checkEmulatorStatus(),
      this.checkDebuggerStatus(),
      this.checkSecureScreenStatus(),
    ]);

    if (isRooted) failureReasons.push('DEVICE_ROOTED');
    if (isEmulator) failureReasons.push('RUNNING_ON_EMULATOR');
    if (isDebuggerAttached) failureReasons.push('DEBUGGER_ATTACHED');
    if (!hasSecureScreen) failureReasons.push('SCREEN_NOT_SECURE');

    let attestationResult: boolean | undefined;
    let integrityToken: string | undefined;

    try {
      if (Platform.OS === 'ios') {
        attestationResult = await this.performiOSAttestation();
      } else {
        const integrityResult = await this.performAndroidIntegrityCheck();
        integrityToken = integrityResult.token;
        attestationResult = integrityResult.valid;
      }
    } catch (error) {
      failureReasons.push('ATTESTATION_FAILED');
      attestationResult = false;
    }

    if (attestationResult === false) {
      failureReasons.push('ATTESTATION_INVALID');
    }

    const status: DeviceSecurityStatus = {
      isRooted,
      isEmulator,
      hasSecureScreen,
      isDebuggerAttached,
      integrityToken,
      attestationResult,
      failureReasons,
    };

    this.cachedStatus = status;
    this.lastCheckTimestamp = now;

    return status;
  }

  private async checkRootStatus(): Promise<boolean> {
    try {
      if (DeviceIntegrityModule?.isRooted) {
        return await DeviceIntegrityModule.isRooted();
      }
      // Fallback heuristic checks
      if (Platform.OS === 'android') {
        return await this.androidRootCheck();
      } else {
        return await this.iosJailbreakCheck();
      }
    } catch {
      return false;
    }
  }

  private async androidRootCheck(): Promise<boolean> {
    try {
      if (DeviceIntegrityModule?.checkRootIndicators) {
        const indicators = await DeviceIntegrityModule.checkRootIndicators();
        return indicators.suBinaryFound ||
               indicators.superuserApkFound ||
               indicators.rootManagementApps ||
               indicators.dangerousProps ||
               indicators.rwSystem;
      }
      return false;
    } catch {
      return false;
    }
  }

  private async iosJailbreakCheck(): Promise<boolean> {
    try {
      if (DeviceIntegrityModule?.checkJailbreakIndicators) {
        const indicators = await DeviceIntegrityModule.checkJailbreakIndicators();
        return indicators.cydiaInstalled ||
               indicators.suspiciousFiles ||
               indicators.canWriteOutsideSandbox ||
               indicators.suspiciousDylibs;
      }
      return false;
    } catch {
      return false;
    }
  }

  private async checkEmulatorStatus(): Promise<boolean> {
    try {
      if (DeviceIntegrityModule?.isEmulator) {
        return await DeviceIntegrityModule.isEmulator();
      }
      return false;
    } catch {
      return false;
    }
  }

  private async checkDebuggerStatus(): Promise<boolean> {
    try {
      if (DeviceIntegrityModule?.isDebuggerAttached) {
        return await DeviceIntegrityModule.isDebuggerAttached();
      }
      if (__DEV__) {
        return true;
      }
      return false;
    } catch {
      return false;
    }
  }

  private async checkSecureScreenStatus(): Promise<boolean> {
    try {
      if (DeviceIntegrityModule?.isScreenSecure) {
        return await DeviceIntegrityModule.isScreenSecure();
      }
      return true;
    } catch {
      return true;
    }
  }

  private async performiOSAttestation(): Promise<boolean> {
    try {
      if (DeviceIntegrityModule?.performAppAttestation) {
        const result = await DeviceIntegrityModule.performAppAttestation();
        return result.valid === true;
      }
      return true;
    } catch {
      return false;
    }
  }

  private async performAndroidIntegrityCheck(): Promise<{ token: string; valid: boolean }> {
    try {
      if (DeviceIntegrityModule?.requestIntegrityToken) {
        return await DeviceIntegrityModule.requestIntegrityToken();
      }
      return { token: '', valid: true };
    } catch {
      return { token: '', valid: false };
    }
  }

  invalidateCache(): void {
    this.cachedStatus = null;
    this.lastCheckTimestamp = 0;
  }
}

// src/security/SecurityGate.ts
import { DeviceSecurityStatus, SecurityPolicy, PaymentError } from '../types/payment';
import { DeviceIntegrityChecker } from './DeviceIntegrityChecker';

const DEFAULT_SECURITY_POLICY: SecurityPolicy = {
  allowRootedDevices: false,
  allowEmulators: false,
  requireAttestation: true,
  requireSecureScreen: true,
  maxTransactionWithoutBiometric: 0,
};

export class SecurityGate {
  private policy: SecurityPolicy;
  private integrityChecker: DeviceIntegrityChecker;

  constructor(policy?: Partial<SecurityPolicy>) {
    this.policy = { ...DEFAULT_SECURITY_POLICY, ...policy };
    this.integrityChecker = DeviceIntegrityChecker.getInstance();
  }

  async validateForPayment(amount: number): Promise<{ allowed: boolean; errors: PaymentError[] }> {
    const errors: PaymentError[] = [];
    const status = await this.integrityChecker.checkDeviceIntegrity();

    if (status.isRooted && !this.policy.allowRootedDevices) {
      errors.push({
        code: 'DEVICE_COMPROMISED',
        message: 'Payment cannot be processed on a rooted/jailbroken device.',
        recoverable: false,
      });
    }

    if (status.isEmulator && !this.policy.allowEmulators) {
      errors.push({
        code: 'EMULATOR_DETECTED',
        message: 'Payment cannot be processed on an emulator.',
        recoverable: false,
      });
    }

    if (status.isDebuggerAttached && !__DEV__) {
      errors.push({
        code: 'DEBUGGER_DETECTED',
        message: 'Payment cannot be processed while a debugger is attached.',
        recoverable: true,
      });
    }

    if (!status.hasSecureScreen && this.policy.requireSecureScreen) {
      errors.push({
        code: 'SCREEN_NOT_SECURE',
        message: 'Please ensure screen capture is disabled for payment processing.',
        recoverable: true,
      });
    }

    if (this.policy.requireAttestation && status.attestationResult === false) {
      errors.push({
        code: 'ATTESTATION_FAILED',
        message: 'Device integrity verification failed.',
        recoverable: false,
      });
    }

    return {
      allowed: errors.length === 0,
      errors,
    };
  }

  async getDeviceStatus(): Promise<DeviceSecurityStatus> {
    return this.integrityChecker.checkDeviceIntegrity();
  }

  updatePolicy(policy: Partial<SecurityPolicy>): void {
    this.policy = { ...this.policy, ...policy };
  }
}

