import { Platform, NativeModules } from 'react-native';

const { SecureStorageModule } = NativeModules;

export class SecureStorage {
  private static readonly KEY_PREFIX = 'payment_';

  static async store(key: string, value: string): Promise<void> {
    const prefixedKey = `${this.KEY_PREFIX}${key}`;

    if (SecureStorageModule?.setItem) {
      await SecureStorageModule.setItem(prefixedKey, value, {
        accessible: Platform.OS === 'ios'
          ? 'AccessibleWhenPasscodeSetThisDeviceOnly'
          : undefined,
        requireAuthentication: false,
      });
    } else {
      // Fallback: In production, this should never be reached
      // as native module must be available
      throw new Error('SecureStorage native module not available');
    }
  }

  static async retrieve(key: string): Promise<string | null> {
    const prefixedKey = `${this.KEY_PREFIX}${key}`;

    if (SecureStorageModule?.getItem) {
      return await SecureStorageModule.getItem(prefixedKey);
    }
    throw new Error('SecureStorage native module not available');
  }

  static async remove(key: string): Promise<void> {
    const prefixedKey = `${this.KEY_PREFIX}${key}`;

    if (SecureStorageModule?.removeItem) {
      await SecureStorageModule.removeItem(prefixedKey);
    }
  }

  static async storeEncrypted(key: string, value: string): Promise<void> {
    if (SecureStorageModule?.setItemWithBiometric) {
      await SecureStorageModule.setItemWithBiometric(
        `${this.KEY_PREFIX}${key}`,
        value,
        {
          requireBiometric: true,
          accessControl: 'BiometryCurrentSet',
        }
      );
    } else {
      await this.store(key, value);
    }
  }

  static async retrieveEncrypted(key: string, promptMessage: string): Promise<string | null> {
    if (SecureStorageModule?.getItemWithBiometric) {
      return await SecureStorageModule.getItemWithBiometric(
        `${this.KEY_PREFIX}${key}`,
        { promptMessage }
      );
    }
    return this.retrieve(key);
  }

  static async clearAll(): Promise<void> {
    if (SecureStorageModule?.clearAllWithPrefix) {
      await SecureStorageModule.clearAllWithPrefix(this.KEY_PREFIX);
    }
  }
}

