// src/security/CertificatePinner.ts
import { Platform } from 'react-native';

export interface PinConfig {
  hostname: string;
  sha256Pins: string[];
  includeSubdomains: boolean;
}

export class CertificatePinner {
  private pins: Map<string, PinConfig> = new Map();

  addPin(config: PinConfig): void {
    this.pins.set(config.hostname, config);
  }

  getPinConfigs(): PinConfig[] {
    return Array.from(this.pins.values());
  }

  getNetworkSecurityConfig(): object {
    const configs = this.getPinConfigs();

    if (Platform.OS === 'android') {
      return {
        'network-security-config': {
          'domain-config': configs.map(config => ({
            domain: {
              '@includeSubdomains': config.includeSubdomains,
              '#text': config.hostname,
            },
            'pin-set': {
              pin: config.sha256Pins.map(pin => ({
                '@digest': 'SHA-256',
                '#text': pin,
              })),
            },
          })),
        },
      };
    }

    // iOS: Return config for TrustKit or similar
    return {
      TSKSwizzleNetworkDelegates: false,
      TSKPinnedDomains: Object.fromEntries(
        configs.map(config => [
          config.hostname,
          {
            TSKIncludeSubdomains: config.includeSubdomains,
            TSKPublicKeyHashes: config.sha256Pins,
            TSKEnforcePinning: true,
          },
        ])
      ),
    };
  }
}

